const Q_CHEMISTRY_2019_MODEL_I=[{"id": "objective>Chemistry>2019-Model-I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A secondary alkanol can be oxidized to give an </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanoic acid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using a suitable oxidizing agent such as acidified dichromatic solution, or acidified permanganate solution, secondary alkanols (alcohols) can be oxidised to alkanones (ketones). <br/> <img src=\"2019-Model-I/1.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2019-Model-I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will give a precipitate with an aqueous solution of copper (I) chloride?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">But-2-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">But-1-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">But-4-yne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">But-1-yne</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Only terminal alkynes (alkynes with the triple bond attached to the first carbon) give a white precipitate on reaction with copper(I)chloride. <br/> <img src=\"2019-Model-I/2.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2019-Model-I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Positive ions in a sea of electrons are found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">covalent bonds.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dative bonds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionic bonds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic bonds.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In metallic bonding, positive metal ions (cations) are surrounded by a \"sea\" of delocalized electrons that move freely throughout the metal lattice. This arrangement creates a cohesive force that holds the metal atoms together. The mobile electrons contribute to the unique properties of metals, such as high electrical and thermal conductivity, malleability, and ductility.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2019-Model-I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A certain hydrocarbon on complete combustion at s.t.p produced 89.6dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and 54g of water. The hydrocarbon should be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the information given in the question <br/> 89.6dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is obtained and 54g of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O from the hydro-carbon <br/>  <br/> Recall: <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> + (x + <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">y</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4</span>)O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → xCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">y</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> 89.6dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> → x <br/> 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> → 1 mole <br/> 22.4x = 89.6 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">89.6<hr size=\"1\" />22.4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4.0</td><td style=\"text-align:center;\">moles</td></tr></table></div> <br/> 54g of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O → K <br/> 18g of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O = 1 mole  <br/>  <br/> 18k = 54 <br/> k = 3.0 moles <br/>  <br/> From the equation given: <br/>  <br/> x = n = 4 --------------- (i) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">k</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">y<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">-------------</td><td style=\"text-align:center;\">(2)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">y<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3</td></tr></table></div> <br/> ∴ y = 6 <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> <br/> The compound is butyne.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2019-Model-I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following equimolar solutions has the highest conductivity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COONa<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> is a strong acid that dissociates into two hydrogen ions (H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>) and one sulfate ion (SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span>) when dissolved in water. This leads to a higher concentration of ions in solution, resulting in higher conductivity.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2019-Model-I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrocarbons which will react with Tollen's reagent conform to the general formula</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n - 2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n + 2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n + 1</span>OH</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alkynes with the general molecular formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n - 2</span> will react with tollen reagent.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2019-Model-I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC name of the compound CF<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CHBrCl is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 - bromo - 2 - chloro- 1, 1, 1 - trifluoroethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 - chloro - 2 - bromo - 1, 1, 1 - trifluoroethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 - bromo - 1 - chloro 2, 2, 2 - trifluoroethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1, 1, 1 trifluoro - 2 - bromo - 2 - trifluoroethane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: CF<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CHBrCl <br/> <img src=\"2019-Model-I/4.png\" style=\"position:relative;max-width:100%;\"/> <br/> 2 - bromo, 2 - chloro, 1, 1, 1 - trifluoroethane.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2019-Model-I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What takes place at the cathode during electrolysis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Anions lose electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Anions are oxidized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cations are discharged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cations are oxidized</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cations are discharged at the cathode during electrolysis. <br/>  <br/> Electrolysis is the process of using an electric current to cause a chemical reaction to take place. The cathode is the negative electrode in an electrolytic cell. It is where cations (positively charged ions) are discharged.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2019-Model-I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Burning magnesium ribbon in air removes which of the following  <br/> (i) oxygen (ii) nitrogen (iii) argon and (iv) carbon(iv)oxide?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i, ii, iii and iv </div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and ii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and iv only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When magnesium ribbon is burned in air, it reacts with oxygen to form magnesium oxide. The other gases present in air such as nitrogen, argon and carbon dioxide do not react with magnesium. Therefore, burning magnesium ribbon in air only removes oxygen.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2019-Model-I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the best starting material for the preparation of oxygen? Heating of trioxonitrate (v) with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pb</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heating of lead trioxonitrate (iv) is the starting material in the production of oxygen. <br/>  <br/> Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → PbO + NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> (in the presence of Δ)</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : OXYGEN AND SULPHUR"}, {"id": "objective>Chemistry>2019-Model-I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following metals is the most essential in the regulation of blood volume, blood pressure and osmotic equilibrium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zinc </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Manganese </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Iron</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium is the most essential metal in the regulation of blood volume, blood pressure and osmotic equilibrium. Sodium ions play a key role in these processes by maintaining the balance of fluids in the body and transmitting nerve impulses.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>2019-Model-I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following alkaline metals react more quickly spontaneously with water?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Strontium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Beryllium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Among the given options, Strontium is the alkaline earth metal that reacts more quickly spontaneously with water. Alkaline earth metals are the elements in Group 2 (IIA) of the periodic table. They are beryllium (Be), magnesium (Mg), calcium (Ca), strontium (Sr), barium (Ba), and radium (Ra). The reactivity of these metals with water increases down the group i.e., Be < Mg < Ca < Sr < Ba < Ra.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALINE-EARTH METALS"}, {"id": "objective>Chemistry>2019-Model-I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When chlorine water is exposed to bright sunlight, the following products are formed </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HOCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> and O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HOCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> and Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> and Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> and O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equation for this reaction is given below <br/> 2HOCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 2HCl + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> (in the presence of sunlight)</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2019-Model-I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which process(es) is/are involved in the turning of starch iodide paper blue-black by chlorine gas?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">iodine attacks the starch to give the blue-black color</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine attacks the starch to give the blue-black color </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine attacks the iodide ion to give the blue-black color </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine oxidizes the iodide ion to produce iodine which attacks the starch to give the blue-black color</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the process of turning starch-iodide paper to black upon reaction with chlorine, chlorine being more electronegative than iodine, attacks iodide ion to give iodine which attacks the starch to give a blue-black color.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2019-Model-I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a set of neutral oxides?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O, SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, CO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O, CO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O, SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, NO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O, Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O, ZnO</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Neutral oxides are oxides that neither show acidic nor basic properties. They are unreactive towards both acids and bases. The oxides that fall into this category are NO (Nitric Oxide), N2O (Nitrous Oxide), CO (Carbon Monoxide), and H2O (Water). Therefore, the set of neutral oxides among the given options is N2O, H2O, CO.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2019-Model-I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The formation of a bond between hydrogen and a highly electronegative atom results in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">polarity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dipole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrovalent bond</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The formation of a bond between hydrogen and a highly electronegative atom results in polarity because the electronegative atom will attract the shared pair of electrons more than the hydrogen atom, creating a dipole with a partial negative charge on the electronegative atom and a partial positive charge on the hydrogen atom.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2019-Model-I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements does not show Rutherford's account of Nuclear Theory? An atom contains a region</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">which is positively charged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">which is massive and can cause deflection of a few projectiles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">which contains protons and neutrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">which is very large and in which close to 98% of projectiles pass undeflected</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rutherford's nuclear theory states that an atom contains a small, dense, positively charged region called the nucleus, which contains protons and neutrons. This nucleus is massive and can cause deflection of a few projectiles. However, the statement that 'an atom contains a region which is very large and in which close to 98% of projectiles pass undeflected' does not align with Rutherford's nuclear theory. According to the theory, the atom is mostly empty space, not a large region.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2019-Model-I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Elements X and Y have electronic configurations 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> and 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span> respectively. When they combine, the formula of the compound formed is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">XY</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Y</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> X = 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> <br/> Y = 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> 3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span> <br/> X = Oxygen (O) <br/> Y = Aluminium (Al) <br/> Aluminium oxide = Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>  <br/> ⇒ Y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2019-Model-I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">By what amount must the temperature of 200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of Nitrogen at 27°C be increased to double the pressure if the final volume is 150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> (Assume ideality)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">150°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">177°C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 27°C = 300K <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>×200<hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>×150<hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">300<hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> 2T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 900 <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 450K - 273= 177°C <br/> To get the temperature it is increased to; <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> -T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 177<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> - 27<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>=150<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2019-Model-I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The combustion of carbon(ii)oxide in oxygen can be represented by equation. <br/> 2CO + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Calculate the volume of the resulting mixture at the end of the reaction if 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of carbon(ii)oxide was exploded in 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">75cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">125cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: The equation of the reaction <br/> 2CO + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Molar Ratio: 2      :      1 → 2 <br/> 2cm CO should react 1cm O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> to give 2cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> CO should react with 25cm O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> to give 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Hence, O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is in excess of 75cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Total resulting gas = 50 + 75 = 125cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2019-Model-I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When ammonia and hydrogen ion bond together to form ammonium ion, the bond formed is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ionic bond </div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrovalent bond </div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent bond </div>", "<div style=\"font-family:Cambria;font-size:17px;\">co-ordinate bond </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When ammonia and hydrogen ion go into bonding, they form ammonium ion by combining with a dative/coordinate covalent bond.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2019-Model-I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following represents the kind of bonding present in ammonium chloride?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ionic only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionic and dative covalent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dative covalent </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl → NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> - Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>    <br/> Where \"-\" signifies <strong>ionic bond</strong> <br/>  <br/> NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> - - - H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> <br/> Where \" - - -\" signifies Co-ordinate covalent bond (dative) <br/>  <br/> <img src=\"2019-Model-I/5.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2019-Model-I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the reaction <br/> A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2B<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 2C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> What will be the effect of a decrease in pressure on the reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rate of forward reaction will increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rate of backward reaction will increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rates of forward and backward reaction are not affected </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the equilibrium will shift </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Le Chatelier's principle, if a dynamic equilibrium is disturbed by changing the conditions, the position of equilibrium moves to counteract the change. In this case, the reaction has more moles of gas on the reactant side (2 moles of B) than on the product side (1 mole of D). Therefore, decreasing the pressure will shift the equilibrium to the side with more moles of gas to increase the pressure again. Hence, the rate of the backward reaction will increase.</div>", "topic": "CHEMICAL EQUILIBRA : DYNAMIC EQUILIBRIUM"}, {"id": "objective>Chemistry>2019-Model-I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 5.0 g of marble reacts with 25.0 cm3 hydrochloric acid, which of the following combinations has the fastest reaction rate?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Marble chips and 2.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> HCl(<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span>)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marble chips and 2.5 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> HCl(<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span>)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Powdered marble and 2.5 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> HCl(<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span>)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Powdered marble and 2.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> HCl(<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span>)</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Powdered marble reacts more rapidly with HCl than the chips of marble because: <br/> Surface area of powdered marble is more that of chips of marble and hence there is more collisions between the molecules of reactants <br/> Number of molecules increases. <br/> Energy of activation decreases <br/> Marble chips will not react with HCl</div>", "topic": "CHEMICAL EQUILIBRA : LE CHATELIER'S PRINCIPLE AND EQUILIBRIUM CONSTANT"}, {"id": "objective>Chemistry>2019-Model-I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reactions is an oxidation process?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cl + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 4e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → 2OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 4e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Oxidation is the loss of electron(s) . There's loss of electrons in the oxygen ion which gives rise to oxidation</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2019-Model-I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If acidified Potassium Dichromate(VI): If acidified Potassium Dichromate(VI) (K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>) acts as oxidizing agent, color changes from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">orange to red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">orange to green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow to green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow to red</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium dichromate is an oxidising agent in organic chemistry. It is used to oxidize alcohols.  <br/>  <br/> In an aqueous solution the color change exhibited can be used to test for distinguishing aldehydes from ketones. Aldehydes reduce dichromate from the +6 to the +3 oxidation state, changing color from orange to green. This color change arises because the aldehyde can be oxidized to the corresponding carboxylic acid.</div>", "topic": "OXIDATION AND REDUCTION : TEST FOR OXIDIZING AND REDUCING AGENTS"}, {"id": "objective>Chemistry>2019-Model-I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The heat of formation of ethene, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is 50KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, and that of ethane, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> is -82KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Calculate the heat evolved in the process: <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-132KJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-122KJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-88KJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-60KJ</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: The equation below  <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> <br/> ΔH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">R</span> = H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span>(C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>) - H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span>(C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>) <br/> ΔH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">θ</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">R</span> = -132KJ/mol</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2019-Model-I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about catalyst is false?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">catalyst do not appear in the balanced equation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">catalyst reduce the activation energy for a reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biological catalysts are called enzymes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">catalysts do not alter the mechanism of the reaction and never appear in the rate low</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Catalysts do alter the mechanism of a reaction by providing a different pathway with a lower activation energy. They do not appear in the rate law because they do not affect the rate constant of the reaction.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2019-Model-I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following does not support the fact that air is a mixture.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it cannot be represented with a chemical formula </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the constituents of air are in a fixed proportion by mass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the constituents of air can be separated by physical means </div>", "<div style=\"font-family:Cambria;font-size:17px;\">none of the above </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The constituents of air are not in a fixed proportion by mass. The proportion of gases in air can vary depending on the location and time, which is a characteristic of a mixture, not a compound.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2019-Model-I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What technique is suitable for separating a binary solution of potassium chloride and potassium trioxochlorate (V)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fractional distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fractional crystallization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Evaporation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Filtration</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fractional crystallization is a method of refining substances based on differences in solubility. It is suitable for separating a binary solution of potassium chloride and potassium trioxochlorate (V) because these two substances have different solubilities.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2019-Model-I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At 27°C, 58.5g of sodium chloride is present in 250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a solution. The solubility of sodium chloride at this temperature is? <br/> (molar mass of sodium chloride = 111.0gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.0 mol/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25 mol/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 mol/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5 mol/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Mass of the salt = 58.9g <br/> Volume = 250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.25dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Mass,</td><td style=\"text-align:center;\">Conc.</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Mass<hr size=\"1\" />Volume</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">58.5<hr size=\"1\" />0.25</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">234g<hr size=\"1\" />dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Solubility</td><td style=\"text-align:center;\">(in</td><td style=\"text-align:center;\">moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">234<hr size=\"1\" />111</td><td style=\"text-align:center;\">≈</td><td style=\"text-align:center;\">2.0 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td></tr></table></div></div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2019-Model-I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following properties increases from left to right along the period but decreases down the group in the Periodic Table? <br/> i. Atomic number <br/> ii. Ionization energy <br/> iii. Metallic character <br/> iv. Electron affinity</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i and ii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iii and iv only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iv only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Atomic number increases from left to right along a period and from top to bottom in a group. Ionization energy generally increases from left to right along a period and decreases down a group. Metallic character decreases from left to right along a period and increases down a group. Electron affinity generally increases from left to right along a period and decreases down a group. Therefore, the properties that increase from left to right along the period but decrease down the group are ionization energy and electron affinity.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2019-Model-I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The molecular shape and bond angle of water are respectively </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bent, 109.5°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetrahedral, 109.5°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bent,105°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">linear, 180°</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019-Model-I/6.png\" style=\"position:relative;max-width:100%;\"/> <br/> The shape of water molecule = Bent/V-shaped  <br/> The bond angle of water = 104.5°/105°.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>2019-Model-I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + 2HCl → 2NaCl + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> The indicator most suitable for this reaction should have a pH equal to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction given is a neutralization reaction where an acid (HCl) reacts with a base (Na2CO3) to form salt and water. The reaction also produces CO2. The reaction will proceed until the acid is completely neutralized, which occurs at a pH of 3. Therefore, the most suitable indicator for this reaction should have a pH equal to 3.</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2019-Model-I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A radioactive nucleus has a half-life of 20 years, starting with 100,000 particles, how many particles will be left exactly at the end of 40 years</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">75,000 particles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">50,000 particles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">35,000 particles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">25,000 particles </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1/2</span> = 20 years <br/> After the first 20 years, half of the substance will have decayed, so we will have 50,000 particle. <br/> After the next 20 years (total of 40 years), another half (half of 50,000) will have decayed, so we will have 25,000 particles.</div>", "topic": "NUCLEAR CHEMISTRY : RADIOACTIVITY"}, {"id": "objective>Chemistry>2019-Model-I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which two gases can be used for the demonstration of the fountain experiment</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and HCl </div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl and NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Two gases that can be used in the study of fountain experiment is ammonia gas and hydrogen chloride gas.  <br/> The experiment introduces concepts like solubility and the gas laws at the entry level. It explains the alkalinity or acidity property of gases when litmus is added to the reaction mixture and shows the colour change by the gas dissolving in water. <br/>  <br/> In fountain experiment, HCl and NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is used. NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is preferred because of the solubility <br/> </div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2019-Model-I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pollutants will lead to the depletion of ozone layer</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorofluorocarbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(ii)oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen sulphide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur(iv)oxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019-Model-I/7.png\" style=\"position:relative;max-width:100%;\"/> <br/> Chlorofluorocarbon is a major pollutant which will contribute to the depletion of ozone layer.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2019-Model-I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following describes the chemical property of acids?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Acid + NaOH → Normal Salt + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Acid + XCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → Salt + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O +NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Acid + X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → Salt + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When acids react with trioxocarbonate (iv) salts, they yield a normal salt, carbon (iv) oxide gas and steam (or water) <br/> e.g 2HCl + CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2019-Model-I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs cannot be represented with a chemical formula?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">air and bronze </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bronze and sodium chloride </div>", "<div style=\"font-family:Cambria;font-size:17px;\">caustic soda and washing soda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper and sodium chloride</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Only elements and compounds can be represented with a chemical formula. Mixtures (such as air, bronze, brass etc) cannot be represented with a chemical formula.</div>", "topic": "CHEMICAL COMBINATION : ELEMENTS COMPOUNDS AND MIXTURES"}, {"id": "objective>Chemistry>2019-Model-I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the equation below: <br/> Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 6Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 14H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → 2Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 6Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 7H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> The oxidation number of chromium changes from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">+7 to +3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+6 to +3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+5 to +3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-2 to +3</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The equation below: <br/> Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span>  + 6Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 14H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → 2Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 6Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 7H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/>  <br/> - The oxidation number of chromium in Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> is 6. <br/>  <br/> - The oxidation number of chromium is 2Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> is +3 <br/>  <br/> - Its oxidation number changes from +6 to +3</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}];
